package com.google.gson.protobuf.generated;

import static org.mockito.Mockito.*;

import com.google.protobuf.ExtensionRegistryLite;
import com.google.protobuf.ExtensionRegistry;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class AnnotationsTest {

  @Test
  void registerAllExtensions_usesExtensionRegistryLite_addsBothExtensions() {
    ExtensionRegistryLite registryLite = mock(ExtensionRegistryLite.class);

    Annotations.registerAllExtensions(registryLite);

    verify(registryLite).add(Annotations.serializedName);
    verify(registryLite).add(Annotations.serializedValue);
    verifyNoMoreInteractions(registryLite);
  }

  @Test
  void registerAllExtensions_usesExtensionRegistry_addsBothExtensions() {
    ExtensionRegistry registry = mock(ExtensionRegistry.class);

    Annotations.registerAllExtensions(registry);

    verify(registry).add(Annotations.serializedName);
    verify(registry).add(Annotations.serializedValue);
    verifyNoMoreInteractions(registry);
  }
}
